1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const coordKey = (x: number, y: number) => `${x},${y}`;
10	
11	const survives = (count: number, wasAlive: boolean): boolean =>
12	  count === 3 || (count === 2 && wasAlive);
13	
14	function countNeighbors(cells: Cell[]): Map<string, { cell: Cell; count: number }> {
15	  const counts = new Map<string, { cell: Cell; count: number }>();
16	  for (const [x, y] of cells) {
17	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
18	      const neighbor: Cell = [x + dx, y + dy];
19	      const k = coordKey(neighbor[0], neighbor[1]);
20	      const entry = counts.get(k);
21	      if (entry) entry.count++;
22	      else counts.set(k, { cell: neighbor, count: 1 });
23	    }
24	  }
25	  return counts;
26	}
27	
28	export function nextGeneration(cells: Cell[]): Cell[] {
29	  const aliveKeys = new Set(cells.map(([x, y]) => coordKey(x, y)));
30	  const result: Cell[] = [];
31	  for (const [k, { cell, count }] of countNeighbors(cells)) {
32	    if (survives(count, aliveKeys.has(k))) result.push(cell);
33	  }
34	  return result;
35	}
