function countNeighbors(cells: Cell[]): Map<string, { cell: Cell; count: number }> {
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const k = coordKey(cell[0], cell[1]);
      const entry = counts.get(k) ?? { cell, count: 0 };
      entry.count++;
      counts.set(k, entry);
    }
  }
  return counts;
}
